#include <bits/stdc++.h>
#include <string>

using namespace std;

string solve(vector<int> n, vector<int> k) {
    long long res = 1;
    for (int i = 0; i <= k[0]; i++) {
        res *= n[0];
    }
    for (int i = 1; i < k.size(); i++) {
        res /= n[i];
    }
    return to_string(res);
}

int main() {
    int t;
    cin >> t;
    while (t--) {
        int n, k;
        cin >> n >> k;
        vector<int> n_array(n), k_array(k);
        for (int i = 0; i < n; i++) {
            cin >> n_array[i];
        }
        for (int i = 0; i < k; i++) {
            cin >> k_array[i];
        }
        cout << solve(n_array, k_array) << endl;
    }
    return 0;
}
